parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let mindMap;

try {
  mindMap = JSON.parse(cleaned);

  if (!Array.isArray(mindMap.branches)) {
    throw new Error("Invalid mind map format");
  }
} catch (error) {
  mindMap = {
    title: "Demo Mind Map",
    center: "Marine Biology",
    description: "A fallback concept map for Study Aura.",
    branches: [
      {
        title: "Marine Mammals",
        summary: "Animals like dolphins and whales that breathe air and nurse their young.",
        keywords: ["dolphins", "whales", "mammals"]
      },
      {
        title: "Coral Reefs",
        summary: "Important marine ecosystems that support biodiversity.",
        keywords: ["coral", "habitat", "biodiversity"]
      }
    ]
  };
}

const branches = mindMap.branches.map((branch) => ({
  title: String(branch.title || "Untitled Branch"),
  summary: String(branch.summary || "Review this concept."),
  keywords: Array.isArray(branch.keywords)
    ? branch.keywords.map((keyword) => String(keyword)).slice(0, 5)
    : ["study", "review"]
}));

return [
  {
    json: {
      mindMap: {
        title: String(mindMap.title || "Study Aura Mind Map"),
        center: String(mindMap.center || "Main Topic"),
        description: String(mindMap.description || "Generated concept map."),
        branches
      },
      fallback: false
    }
  }
];

